    -fx-border-width: 1;
    -fx-border-radius: 3;
    -fx-background-radius: 3;
    -fx-pref-width: 80px;
    -fx-padding: 4;
    -fx-text-fill: #1A5276;
    -fx-prompt-text-fill: #85C1E9;
