    -fx-font-size: 12px;
    -fx-background-color: #E8F4FD;
    -fx-border-color: #5DADE2;
    -fx-border-width: 1;
    -fx-border-radius: 3;
    -fx-background-radius: 3;
    -fx-pref-width: 180px;
