    -fx-text-fill: #FFFFFF;
    -fx-background-color: #2E86C1;
    -fx-border-color: #1A5276;
    -fx-border-width: 2;
    -fx-border-radius: 4;
    -fx-background-radius: 4;
    -fx-padding: 10 30;
