    -fx-effect: dropshadow(gaussian, #5DADE2, 4, 0.3, 0, 2);
}

.btn-recommend:hover {
    -fx-background-color: #3498DB;
    -fx-effect: dropshadow(gaussian, #2E86C1, 6, 0.5, 0, 3);
