@echo off
REM ===================================================================
REM build.bat — Compile and run the Spotify Music Recommendation System
REM ===================================================================
REM Requirements:
REM   - Java 17+ with JavaFX SDK installed
REM   - JAVA_HOME set
REM   - JavaFX SDK path configured below
REM
REM Usage:
REM   build.bat          — Compile only
REM   build.bat run      — Compile and run
REM ===================================================================

setlocal EnableDelayedExpansion

REM ---- Configuration ----
REM Adjust this path to match your JavaFX SDK installation
REM Example: C:\javafx-sdk-21.0.1\lib
set JAVAFX_LIB=

REM Source and output directories
set SRC_DIR=src
set OUT_DIR=out
set MAIN_CLASS=spotify.Main

REM ---- Check if Java is available ----
where java >nul 2>&1
if %ERRORLEVEL% NEQ 0 (
    echo [ERROR] Java not found. Please install Java 17+ and add it to PATH.
    pause
    exit /b 1
)

where javac >nul 2>&1
if %ERRORLEVEL% NEQ 0 (
    echo [ERROR] javac not found. Please install JDK 17+ and add it to PATH.
    pause
    exit /b 1
)

echo ============================================
echo   Spotify Music Recommendation System
echo   Build Script
echo ============================================
echo.

REM ---- Create output directory ----
if not exist %OUT_DIR% (
    mkdir %OUT_DIR%
    echo [INFO] Created output directory: %OUT_DIR%
)

REM ---- Clean previous build ----
echo [INFO] Cleaning previous build...
if exist %OUT_DIR%\spotify (
    rmdir /s /q %OUT_DIR%\spotify
)

REM ---- Discover all Java source files ----
echo [INFO] Discovering source files...
set SRC_FILES=
for /r %SRC_DIR% %%f in (*.java) do (
    set SRC_FILES=!SRC_FILES! "%%f"
)

if "!SRC_FILES!"=="" (
    echo [ERROR] No Java source files found in %SRC_DIR%.
    pause
    exit /b 1
)

REM ---- Compile ----
echo [INFO] Compiling...
echo.

if "!JAVAFX_LIB!"=="" (
    REM Try to compile without explicit JavaFX module path
    REM (works if JavaFX is on the module path by default)
    javac -d %OUT_DIR% --enable-preview -source 21 !SRC_FILES! 2>nul
    if !ERRORLEVEL! NEQ 0 (
        REM Retry without preview flag
        javac -d %OUT_DIR% !SRC_FILES! 2>nul
        if !ERRORLEVEL! NEQ 0 (
            echo [ERROR] Compilation failed.
            echo.
            echo   If you see 'package javafx.application is not visible' errors,
            echo   you need to set the JAVAFX_LIB variable in this script to
            echo   your JavaFX SDK lib directory.
            echo.
            echo   Example: set JAVAFX_LIB=C:\javafx-sdk-21.0.1\lib
            echo.
            REM Try with module-path approach using environment detection
            echo [INFO] Attempting compilation with JavaFX module path autodetection...
            call :autodetect_and_compile
        )
    )
) else (
    javac -d %OUT_DIR% --module-path "!JAVAFX_LIB!" --add-modules javafx.controls,javafx.fxml !SRC_FILES!
    if !ERRORLEVEL! NEQ 0 (
        echo [ERROR] Compilation failed. Check the errors above.
        pause
        exit /b 1
    )
)

echo.
echo ============================================
echo   BUILD SUCCESSFUL
echo   Output directory: %OUT_DIR%
echo ============================================
echo.

REM ---- Run if requested ----
if /i "%~1"=="run" (
    call :run_app
) else (
    echo To run the application:
    echo   build.bat run
    echo.
    echo Or directly:
    if not "!JAVAFX_LIB!"=="" (
        echo   java --module-path "!JAVAFX_LIB!" --add-modules javafx.controls -cp out %MAIN_CLASS%
    ) else (
        echo   java --module-path ^<JAVAFX_LIB^> --add-modules javafx.controls -cp out %MAIN_CLASS%
    )
)

endlocal
pause
exit /b 0

REM ---- Subroutines ----

:autodetect_and_compile
    REM Try to find JavaFX in common locations
    set FOUND_FX=0

    REM Check JAVA_FX_HOME
    if defined JAVA_FX_HOME (
        if exist "!JAVA_FX_HOME!\lib\javafx.controls.jar" (
            set JAVAFX_LIB=!JAVA_FX_HOME!\lib
            set FOUND_FX=1
        )
    )

    REM Check PATH for javafx
    if !FOUND_FX! EQU 0 (
        for %%p in (
            "C:\javafx-sdk-21.0.1\lib"
            "C:\javafx-sdk-21\lib"
            "C:\javafx-sdk-17.0.9\lib"
            "C:\Program Files\Java\javafx-sdk\lib"
        ) do (
            if exist "%%~p\javafx.controls.jar" (
                set JAVAFX_LIB=%%~p
                set FOUND_FX=1
                goto :found_fx
            )
        )
    )

:found_fx
    if !FOUND_FX! EQU 1 (
        echo [INFO] Found JavaFX at: !JAVAFX_LIB!
        javac -d %OUT_DIR% --module-path "!JAVAFX_LIB!" --add-modules javafx.controls,javafx.fxml !SRC_FILES!
        if !ERRORLEVEL! NEQ 0 (
            echo [ERROR] Compilation still failed. Check errors above.
            pause
            exit /b 1
        )
    ) else (
        echo [ERROR] Could not find JavaFX SDK.
        echo.
        echo   Please download JavaFX SDK from: https://gluonhq.com/products/javafx/
        echo   Extract it and set JAVAFX_LIB in this script.
        echo.
        echo   Example: set JAVAFX_LIB=C:\javafx-sdk-21.0.1\lib
        echo.
        pause
        exit /b 1
    )
    goto :eof

:run_app
    echo.
    echo [INFO] Starting application...
    echo.

    if not "!JAVAFX_LIB!"=="" (
        java --module-path "!JAVAFX_LIB!" --add-modules javafx.controls,javafx.fxml -cp %OUT_DIR% %MAIN_CLASS%
    ) else (
        echo [ERROR] JavaFX lib path not set. Cannot run.
        echo Set JAVAFX_LIB in build.bat and try again.
    )
    goto :eof

